var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아직 늦지 않았습니다!","JPN":"まだ間に合います！　","ENG":"It's not too late!","TWN":"現在還來得及！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"당장 추적해야 합니다, 사령관님!","JPN":"今すぐ追跡しなければ、司令官！","ENG":"We need to follow them, Commander!","TWN":"我們要立刻追擊，司令官！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"바보 같은 소리 말게, 도미닉.","JPN":"馬鹿を言うんじゃない、ドミニーク。","ENG":"Stop being so foolish, Dominic.","TWN":"別說傻話了，多明尼克。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"싸워 봤으니 잘 알겠지? 저들은 도망친 게 아니라 그저 물러났을 뿐이야.","JPN":"一度戦ってるし、わかるだろ？　あいつらは逃げたんじゃない、退却しただけだ。","ENG":"You fought them. They didn't run away; they left us.","TWN":"你和他們戰鬥過了，應該很清楚吧？他們不是逃跑，只是撤退而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금 이 순간에도 우리의 퇴각로를 확보하기 위해 차원 폭풍 밖에서 제이크와 다른 동료들이 싸우고 있지.","JPN":"今この瞬間にも、次元の暴風の外ではジェイクらが我々の退却路を確保するために戦っている。","ENG":"And right now, Jake and the others are fighting outside this dimensional storm to secure a safe retreat route for us.","TWN":"現在這個當下，傑克和其他同伴們為了確保我們的退路，還在次元風暴外戰鬥著。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데도 무리한 전투를 계속할 셈인가?","JPN":"それでも無謀な戦闘を続けるつもりか？","ENG":"Do you really want to ignore their struggle to go chase after them?","TWN":"即使如此，你還要繼續這種不合理的戰鬥嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다. 이번 작전은 실패로군요.","JPN":"了解しました。今回の作戦は失敗ですね。","ENG":"Understood. Looks like this operation has failed.","TWN":"我知道了。這次作戰失敗了呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"작전의 중요도에 비추어 볼 때, 저도 징계를 피하긴 힘들 겁니다.","JPN":"作戦の重要度からして、私も懲戒を免れないでしょう。","ENG":"Given its significance, there's no way I can avoid punishment.","TWN":"考慮到這次作戰的重要性，我應該也難逃處分吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"정보부에서 잘리게 되면 갈 곳이나 생각해 둬야겠군요.","JPN":"情報局をクビになった後のことを考えておかねば。","ENG":"Or stay at the Intelligence Agency for that matter. I'd better look for a new job.","TWN":"如果被情報部裁掉的話，我得想想還有什麼可以去的地方了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"고맙네. 자네가 앞으로 무슨 일을 하게 되든 내가 최선을 다해 돕도록 하지.","JPN":"すまない。君が今後どんな仕事に就こうとも、私が全力でバックアップするよ。","ENG":"Thank you. Wherever you go, I'll do my best to help you.","TWN":"謝謝你。無論你以後做什麼工作，我都會盡我的全力幫助你的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......기대도 안 할 테니 훼방이나 놓지 마십시오.","JPN":"……それは望み薄だと思うので、どうかご放念を。","ENG":"No, thanks. Just stay out of my way.","TWN":"……我完全不期待，所以不要妨礙我。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"불길한 소리가 나는군. 나쁜 예감이 드는데?","JPN":"不吉な音だ。イヤな予感がするぞ。","ENG":"What's that ominous-sounding noise? It doesn't bode well for us.","TWN":"這什麼不祥的聲音，我有種不好的預感啊？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설마......?","JPN":"まさか……？","ENG":"Is it...","TWN":"難道……?"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이런! 함을 포위하고 있던 침식체들이 달려들고 있습니다!","JPN":"艦船を取り囲んでいた侵食体どもが暴れています！　","ENG":"Oh, no! The C.O.s around the ship—they're coming at us!","TWN":"天哪！包圍艦船的侵蝕體向這裡殺過來了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아마도 함 내에 있던 불멸체 코어가 사라진 영향 때문인 것 같습니다!","JPN":"おそらく艦船内にいた不滅体コアが消えたせいかと！　","ENG":"Probably because the Immortal System Core is gone!","TWN":"大概是因為艦船內的不滅者核心消失造成的！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"불멸체 코어가 대체 뭐길래 저 녀석들이 흥분하는 거지?","JPN":"あいつらがあんなに暴れだすとは、いったい不滅体コアが何だと言うのだ？","ENG":"What the hell is that Immortal System Core that excites them so much?","TWN":"不滅者核心到底是什麼東西，讓這些傢伙這麼興奮啊？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저도 이유는 모릅니다. 하지만 침식체란 것들의 행동패턴은 단순하고 명확하죠.","JPN":"私も理由はわかりません。ただ、侵食体どもの行動パターンは単純明快です。","ENG":"I don't exactly know. But C.O.s are simple, intuitive creatures.","TWN":"我也不知道為什麼。但侵蝕體這種生物的行動模式，是簡單明確的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이터니움에 이끌리는 여느 침식체들처럼, 놈들도 유물이 있는 로스트 쉽의 주변을 어슬렁거리며 파수꾼 역할을 하고 있는 겁니다.","JPN":"エタニウムに惹かれる侵食体のように、\\n奴らもロストシップのまわりをうろついて遺物の番人をつとめているのです。","ENG":"They're attracted to Artifacts in Lost Ships, just like they're attracted to Eternium. They hang around, acting as watchmen.","TWN":"就像侵蝕體通常會被永恆之金所吸引那樣，那些傢伙也在失落艦船周圍閒晃，擔任守衛的角色。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 그자들이 유물을 가지고 사라졌다는 걸 감지하고 이쪽으로 오는 것인가?","JPN":"つまり、あの連中に遺物が持ち去られたことを感知してこちらにやってきているということか？","ENG":"You mean, they're coming now because they've noticed the Artifact is gone?","TWN":"那麼，它們是察覺到那幾個人帶著遺物消失，所以往這邊來的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어지간해선 꿈쩍도 안 하는 자네가 그렇게 흥분할 정도면, 우리가 처한 상황이 꽤 위험한 모양이군?","JPN":"滅多なことでは動じない君がそこまで興奮するとは。\\n我々の置かれた状況はかなり危険なんだな？","ENG":"You rarely lose your composure. Are we in a dire situation?","TWN":"你們明明完全無法動彈卻這麼激動，看來我們現在處境不是一般得危險啊？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"순도 높은 이터니움이 있는 곳일수록 고위 침식체가 있을 확률이 높다는 건 알고 계시겠죠.","JPN":"エタニウムの純度が高いほど、その周りに高位侵食体がいる確率が高いのはご存じかと。","ENG":"You know high-purity Eternium attracts high-ranking C.O.s, right?","TWN":"您應該知道吧，永恆之金純度越高，就越可能出現高等侵蝕體。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 로스트 쉽에 있던 유물인 불멸체 코어 또한 마찬가지입니다.","JPN":"このロストシップに載せられていた遺物、不滅体コアも同じです。","ENG":"The Artifact that was on this Lost Ship, the Immortal System Core,","TWN":"曾在這艘失落艦船裡的不滅者核心也一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제가 정보부에서 얻은 경험과 이번 임무의 중요도로 미뤄볼 땐...... 그건 분명 최고 등급의 구 관리국 유물입니다.","JPN":"私の情報局での経験や任務の重要度を踏まえると……\\nあれはきっと、最高ランクの旧管理局遺物です。","ENG":"was one of the highest-graded legacies of the Old Administration, as far as I can tell based on my experience as an intelligence agent and the importance of this mission.","TWN":"根據我在情報部的經驗，並結合這次任務的重要程度來推斷……這明顯是舊管理局最高等級的遺物。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그러니 이 유물을 지키고 있던 것은 적어도......","JPN":"ですから、この遺物を守っていたのは少なくとも……","ENG":"So, these C.O.s that the Artifact has attracted have to be at least...","TWN":"所以守護這個遺物的，應該至少是……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"적어도?","JPN":"少なくとも？","ENG":"At least?","TWN":"至少是？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체일 가능성이 큽니다!","JPN":"第4種侵食体である可能性が高いです！","ENG":"... Category 4.","TWN":"很有可能是4類侵蝕體！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"4종이라고? 정말인가?","JPN":"第4種？　本当か？","ENG":"Category 4? Are you serious?","TWN":"4類？真的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저 포효소리가 답이 되겠군요!","JPN":"あの咆哮がその証と言えるでしょう！","ENG":"That roaring sound is a good answer.","TWN":"聽那個咆哮聲應該就有答案了吧！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......확실히 심상치 않은 놈이로군.","JPN":"……確かに並大抵の奴ではない。","ENG":"It definitely sounds alarming enough.","TWN":"……確實不是普通的傢伙呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"몸을 피하시죠. 제가 시간을 벌어보겠습니다.","JPN":"ひとまず避難を。私が時間稼ぎしてみます。","ENG":"You should leave. I'll stall it for time.","TWN":"請您躲開吧，我來爭取時間。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니. 그럴 필요 없네. 어차피 녀석을 여기서 저지하지 못하면 끝까지 쫓아올 거야.","JPN":"いや、そんな必要はない。\\nどのみち奴をここで食い止めなければ、どこまでも追いかけてくるだろう。","ENG":"No, don't. If we don't stop it right here and now, it won't stop following us.","TWN":"不，沒有這個必要。我們如果不在這裡解決掉這群傢伙，它們到天涯海角都會追上來的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 아무리 사령관님이라도 지원 없이 4종 녀석과 정면에서 맞서는 건 불가능합니다!","JPN":"ですが、いくら司令官でも支援なしで第4種と正面対決することはできません！","ENG":"But Commander, even you can't fight a Category 4 C.O. without support.","TWN":"可是，就算是司令官大人，也不可能在沒有支援的情況下，與4類侵蝕體正面對抗啊！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아. 자네가 없는 사이에, 우리도 변화 없이 빈둥대고 있지만은 않았거든.","JPN":"心配ない。君がいない間に私たちも遊んでたわけではないのさ。","ENG":"I'll be fine. We didn't just laze around in your absence.","TWN":"沒關係。你不在的這段時間，我們可不是毫無長進、遊手好閒地度過的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"예? 그게 무슨......","JPN":"はい？　それはどういう……","ENG":"Huh? What do you mean?","TWN":"嗯？您是說……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아- 여기는 마리아 안토노프 소장. 통신상태는 양호한가?","JPN":"こちらマリア・アントノフ少将だ。通信状態はどうだ？","ENG":"Ah, this is Major General Maria Antonov. Can you hear me?","TWN":"啊——這裡是瑪麗亞·安東諾夫少將。通信狀態是否良好？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L44_1","type":"dialog","speaker":"AI_DELTA_NULL_NULL","text":{"KOREA":"여기는 델타 세븐 제1 기갑 분견대. 수신 양호.","JPN":"こちらデルタセブンの第1機甲支隊。通信状態は良好。","ENG":"This is the First Armored Detachment of Delta Seven. I can hear you.","TWN":"這裡是第七三角洲第一裝甲分隊，通信良好。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"현장 지휘권자의 재량에 따라, 현 시간부로 대 침식전을 개시한다.","JPN":"現場の指揮権者の裁量によって、現時刻より対侵食戦を開始する。","ENG":"As the field commander, I hereby order the initialization of an anti-Corruption operation.","TWN":"根據現場指揮者的判斷，現時間點，開始進行侵蝕戰。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AI_DELTA_NULL_NULL","text":{"KOREA":"네. 전 기체 정비를 마치고 워프 포인트에서 대기 중입니다.","JPN":"はい。すべての機体整備を完了して、ワープポイントで待機しています。","ENG":"Yes, ma'am. All vehicles and aircraft have been maintained and now on standby at the warp point.","TWN":"是。所有機體準備完畢，正在躍傳點待機。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L50_1","type":"dialog","speaker":"AI_DELTA_NULL_NULL","text":{"KOREA":"타격 대상은?","JPN":"攻撃対象は？","ENG":"What's our target?","TWN":"打擊對象是？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"타격 목표는 4종으로 추정되는 침식체다.","JPN":"攻撃目標は、第4種とみられる侵食体だ。","ENG":"A C.O., suspected Category 4.","TWN":"打擊目標是推測為4類的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AI_DELTA_NULL_NULL","text":{"KOREA":"대 고위 침식전 탄약 적재 완료. 사령관님의 소환을 기다립니다.","JPN":"高位侵食戦のための弾薬搬入を完了。司令官からの指示を待っています。","ENG":"Finished loading high-caliber anti-Corruption ammo. Waiting for your summons, Commander.","TWN":"高等侵蝕戰專用彈藥裝載完成。等待司令官大人的命令。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋아. 목표 완전 박멸까지 탄약을 아끼지 말도록.","JPN":"よし、目標の完全撲滅まで弾薬を惜しまないように。","ENG":"Good. Spare no ammo until the target is completely annihilated.","TWN":"很好。到目標完全消滅為止，不要吝惜彈藥，開火。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이건...... 설마 본부에 있던 지원 기갑사단?","JPN":"これは……まさか本部にいた機甲師団の支援隊？","ENG":"Is this the support armored division that was in HQ?","TWN":"這……難道是在本部的支援裝甲團？"},"stage":{"bg":"SS_DELTA_03","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LAND"},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 실비아가 내 능력을 활용할 수 있는 썩 괜찮은 아이디어를 내줘서 말이야.","JPN":"そうだ、シルビアが私の能力を活用できる\\nなかなか良いアイデアを出してくれたんだ。","ENG":"That's right. Sylvia helped me figure out a way to make good use of my ability.","TWN":"是的。這是希爾維亞出的主意，讓我能充分發揮我的能力。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......차원 폭풍 속에서도 이 정도의 대규모 위상 전환을 성공시키시다니.","JPN":"……次元の暴風の中でこれだけの大型位相転換を成功させるとは。","ENG":"You've managed such a large-scale phasal shift in the middle of a dimensional storm.","TWN":"……竟然能在次元風暴中，成功轉換這麼大規模的能量。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"세월이 흘러도 실력은 여전하시군요.","JPN":"月日が経っても、相変わらずの腕前ですね。","ENG":"You're still good, Commander.","TWN":"就算歲月流逝，您的實力還是依舊不減呢。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아부는 저 골칫거리부터 처리한 뒤에나 듣도록 하지.","JPN":"お世辞はあの厄介者を片づけてから聞くとしよう。","ENG":"You can flatter me after we're finished with that thing.","TWN":"拍馬屁等這些麻煩事解決之後再說吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};